import { formatCurrency } from "@final-evaluation/shared";
import { useEffect, useMemo, useState } from "react";
import { useOutletContext } from "react-router-dom";
import { adminApi } from "../api/client.js";
import styles from "./OrderLinePage.module.css";

const CARD_THEME = {
  processing: {
    shell: "#F6DFB8",
    badge: "#FFE3BC",
    badgeText: "#2C2C2E",
    button: "#E5A13C",
    buttonText: "#FFF9F0",
    icon: "#5B4625",
  },
  takeaway: {
    shell: "#C2D4D9",
    badge: "#C2D4D9",
    badgeText: "#3B413D",
    button: "#9BAEB3",
    buttonText: "#3B413D",
    icon: "#3B413D",
  },
  done: {
    shell: "#AEE8B7",
    badge: "#AEE8B7",
    badgeText: "#245231",
    button: "#2ADD57",
    buttonText: "#F6FFF7",
    icon: "#245231",
  },
};

function clockLabel(createdAt) {
  return new Date(createdAt).toLocaleTimeString("en-US", {
    hour: "numeric",
    minute: "2-digit",
    hour12: true,
  });
}

function orderMatches(query, order) {
  if (!query) {
    return true;
  }

  return `${order.publicOrderId} ${order.customer.name} ${order.type} ${order.tableNumber || "takeaway"}`
    .toLowerCase()
    .includes(query.toLowerCase());
}

function ticketTone(order) {
  if (order.type === "takeaway") {
    if (order.remainingMinutes > 0) {
      return "processing";
    }

    if (order.remainingDeliveryMinutes > 0) {
      return "takeaway";
    }

    return "done";
  }

  if (order.queueStatus === "done") {
    return "done";
  }

  return "processing";
}

function badgeLines(order) {
  if (order.type === "takeaway") {
    if (order.remainingMinutes > 0) {
      return {
        primary: "Take Away",
        secondary: `Ongoing: ${Math.max(1, order.remainingMinutes)} Min`,
      };
    }

    if (order.remainingDeliveryMinutes > 0) {
      return { primary: "Take Away", secondary: "Not Picked Up" };
    }

    return { primary: "Done", secondary: "Served" };
  }

  if (order.queueStatus === "done") {
    return { primary: "Done", secondary: "Served" };
  }

  return {
    primary: "Dine In",
    secondary: `Ongoing: ${Math.max(1, order.remainingMinutes)} Min`,
  };
}

function footerLabel(order) {
  if (order.type === "takeaway") {
    if (order.remainingMinutes > 0) {
      return "Processing";
    }

    return "Order Done";
  }

  if (order.queueStatus === "done") {
    return "Order Done";
  }

  return "Processing";
}

function cardTitle(order) {
  if (order.type === "takeaway") {
    return "Take Away";
  }

  if (!order.tableNumber) {
    return "Dine In";
  }

  return `Table-${String(order.tableNumber).padStart(2, "0")}`;
}

function itemCountLabel(order) {
  return `${order.itemCount} Item`;
}

