function OrderCard({ order }) {
  const tone = ticketTone(order);
  const theme = CARD_THEME[tone];
  const badge = badgeLines(order);
  const orderCode = `#${order.publicOrderId.replace("ORD-", "")}`;
  const items = order.items.slice(0, 3);
  const footerClassName =
    tone === "done"
      ? styles.footerBadgeDone
      : tone === "processing"
        ? styles.footerBadgeProcessing
        : styles.footerBadgeTakeaway;

  return (
    <article className={styles.card}>
      <OrderCardFrame tone={tone} />

      <div className={styles.cardLayer}>
        <div className={styles.metaPanel}>
          <span className={styles.orderCode}>{orderCode}</span>
          <span className={styles.topInfoLine}>{cardTitle(order)}</span>
          <span className={styles.topInfoLine}>{clockLabel(order.createdAt)}</span>
          <span className={styles.topInfoLine}>{itemCountLabel(order)}</span>
        </div>

        <div className={styles.badgePanel} style={{ color: theme.badgeText }}>
          <strong>{badge.primary}</strong>
          <span>{badge.secondary}</span>
        </div>

        <div className={styles.contentPanel}>
          <div className={styles.ticketList}>
            {items.map((item) => (
              <div key={item.menuItemId} className={styles.ticketRow}>
                <span>{item.quantity} x</span>
                <span>{item.name}</span>
              </div>
            ))}
          </div>

          <div className={styles.cardBottom}>
            <span className={styles.customer}>{order.customer.name}</span>
            <span className={styles.total}>{formatCurrency(order.totalAmount)}</span>
          </div>
        </div>

        <div className={`${styles.footerBadge} ${footerClassName}`}>
          <FooterBadge tone={tone} label={footerLabel(order)} />
        </div>
      </div>
    </article>
  );
}

export function OrderLinePage() {
  const { searchQuery } = useOutletContext();
  const [orders, setOrders] = useState([]);
  const [error, setError] = useState("");

  useEffect(() => {
    adminApi
      .getOrders("all")
      .then(setOrders)
      .catch((requestError) => setError(requestError.message));
  }, []);

  const visibleOrders = useMemo(
    () =>
      orders
        .filter((order) => orderMatches(searchQuery, order))
        .sort((left, right) => left.publicOrderId.localeCompare(right.publicOrderId)),
    [orders, searchQuery],
  );

  return (
    <section className={styles.page}>
      {error ? <p className={styles.error}>{error}</p> : null}

      <div
        className={`${styles.grid} ${
          visibleOrders.length <= 8 ? styles.gridCompact : styles.gridOverflow
        }`}
      >
        {visibleOrders.map((order) => (
          <OrderCard key={order._id} order={order} />
        ))}
      </div>
    </section>
  );
}
